const fs = require('fs');
const path = require('path');
const dir = 'src/content/exams/logique';

function write(filename, data) {
  fs.writeFileSync(path.join(dir, filename), JSON.stringify(data, null, 2));
  console.log('wrote ' + filename);
}
function exam(id, title, emoji, order, facile, moyen, difficile) {
  return { id, category:'logique', categoryLabel:'Logique', categoryEmoji:'🧠', categoryOrder:10, title, emoji, order,
    levels:{ facile:{passPercent:60,questions:facile}, moyen:{passPercent:65,questions:moyen}, difficile:{passPercent:70,questions:difficile} } };
}
function q(id,prompt,prompt_nl,prompt_en,prompt_es,options,answer,cor,cor_nl,cor_en,cor_es){
  return {id,type:'mcq',prompt,prompt_nl,prompt_en,prompt_es,options,answer,correction:cor,correction_nl:cor_nl,correction_en:cor_en,correction_es:cor_es};
}

